function solve(n, edges, k) {
    // Sort edges by their removal time
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize parent array for Union-Find
    const parent = Array(n).fill(0).map((_, i) => i);

    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x, y) {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX !== rootY) {
            parent[rootY] = rootX;
        }
    }

    // Process all edges to find initial connected components
    for (const [u, v, time] of edges) {
        union(u, v);
    }

