fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let mut edges = edges;
    edges.sort_by(|a, b| a[2].cmp(&b[2]));

    let mut low = 0;
    let mut high = if edges.is_empty() { 0 } else { edges[edges.len() - 1][2] };
    let mut answer = high;

    while low <= high {
        let mid = (low + high) / 2;
        if check(n, &edges, mid, k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    answer
}

fn check(n: i64, edges: &[Vec<i64>], t: i64, k: i64) -> bool {
    let mut adj = vec![vec![]; n as usize];
    for edge in edges {
        if edge[2] > t {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
