fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    if k == n {
        return 0;
    }
    let mut max_time = 0;
    if !edges.is_empty() {
        max_time = edges.iter().map(|e| e[2]).max().unwrap();
    }
    let mut low = 0;
    let mut high = max_time;
    let mut answer = max_time;
    while low <= high {
        let mid = (low + high) / 2;
        let count = count_components(n, &edges, mid);
        if count >= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    answer
}

fn count_components(n: i64, edges: &Vec<Vec<i64>>, t: i64) -> i64 {
    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let time = edge[2];
        if time > t {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            adj[u].push(v);
            adj[v].push(u);
        }
    }
    let mut visited = vec![false; n];
    let mut count = 0;
    for i in 0..n {
        if !visited[i] {
            count += 1;
            let mut stack = vec![i];
            visited[i] = true;
            while let Some(node) = stack.pop() {
                for &neighbor in &adj[node] {
                    if !visited[neighbor] {
                        visited[neighbor] = true;
                        stack.push(neighbor);
                    }
                }
            }
        }
    }
    count as i64
}
