struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent = (0..n).map(|i| i).collect();
        let rank = vec![1; n];
        DSU { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return false;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            if self.rank[x_root] == self.rank[y_root] {
                self.rank[x_root] += 1;
            }
        }
        true
    }

    fn count_components(&self) -> usize {
        let mut count = 0;
        for i in 0..self.parent.len() {
            if self.find(i) == i {
                count += 1;
            }
        }
        count
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    if edges.is_empty() {
        return 0;
    }

    let max_time = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut low = 0;
    let mut high = max_time as i64;
    let mut answer = high;

    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n);
        for edge in edges {
            let time = edge[2];
            if time > mid {
                let u = edge[0] as usize;
                let v = edge[1] as usize;
                dsu.union(u, v);
            }
        }
        let count = dsu.count_components();
        if count >= k as usize {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    answer
}
